"""Chain reachability lint for SKF workflow skills.

For each `src/skf-*/` workflow skill, asserts:

1. Every step-file path listed in SKILL.md's Stages table exists on disk.
2. Every `nextStepFile` value in step-file frontmatter resolves to an existing
   file (or to a recognised external target such as `shared/health-check.md`).
3. Every step file (anything with a `nextStepFile` frontmatter key) is
   reachable from the SKILL.md entry set by walking the `nextStepFile` chain.

The entry set is every `references/...md` path SKILL.md mentions — the
Stages table for the main flow, plus conditional entries invoked from
On Activation (e.g. `--batch` loading `references/batch-mode.md` in
skf-quick-skill before the main pipeline starts).

The third check is the safety net: it catches step files that exist on disk
but no chain reaches — the failure mode the dropped "Workflow Rules" trio
only claimed to prevent. `skf-forger` is excluded because it is an agent
persona, not a chained workflow.
"""

from __future__ import annotations

import pathlib
import re
from collections import deque

import pytest

REPO_ROOT = pathlib.Path(__file__).resolve().parent.parent
SRC = REPO_ROOT / "src"

WORKFLOW_SKILLS = sorted(
    d.name
    for d in SRC.iterdir()
    if d.is_dir() and d.name.startswith("skf-") and d.name != "skf-forger"
)

# `nextStepFile` values that resolve outside the skill directory.
# `shared/health-check.md` resolves from the SKF module root (src/ in dev,
# {project-root}/_bmad/skf/ when installed), per the comment in
# `references/health-check.md` step files.
EXTERNAL_TARGETS = {"shared/health-check.md"}


def _read_frontmatter(file_path: pathlib.Path) -> str | None:
    """Return the raw YAML frontmatter block (without the `---` fences), or None."""
    text = file_path.read_text(encoding="utf-8")
    match = re.match(r"^---\n(.*?)\n---\n", text, re.DOTALL)
    return match.group(1) if match else None


def _next_step(file_path: pathlib.Path) -> str | None:
    """Extract the `nextStepFile` value from a step file's frontmatter."""
    fm = _read_frontmatter(file_path)
    if fm is None:
        return None
    match = re.search(
        r"^nextStepFile:\s*['\"]?([^'\"\n]+?)['\"]?\s*$",
        fm,
        re.MULTILINE,
    )
    return match.group(1).strip() if match else None


_REFERENCES_PATH_RE = re.compile(r"\breferences/[A-Za-z0-9_./-]+\.md\b")


def _stages_entries(skill_md: pathlib.Path) -> list[str]:
    """Extract `references/...md` paths from the SKILL.md `## Stages` table only."""
    text = skill_md.read_text(encoding="utf-8")
    section = re.search(
        r"^## Stages\b(.*?)(?=^## )", text, flags=re.MULTILINE | re.DOTALL
    )
    if not section:
        return []
    return _REFERENCES_PATH_RE.findall(section.group(1))


def _skill_md_entries(skill_md: pathlib.Path) -> list[str]:
    """Every `references/...md` path SKILL.md mentions — main flow entries plus
    conditional entries invoked from On Activation (e.g. `--batch` modes)."""
    text = skill_md.read_text(encoding="utf-8")
    return list(dict.fromkeys(_REFERENCES_PATH_RE.findall(text)))


def _resolve_next(current: pathlib.Path, next_value: str) -> pathlib.Path | None:
    """Resolve a nextStepFile value to an absolute path, or None for external targets."""
    if next_value in EXTERNAL_TARGETS:
        return None
    return (current.parent / next_value).resolve()


def _skill_inventory(skill: str) -> dict:
    """Collect Stages entries, step files, and all references/*.md for one skill."""
    skill_dir = SRC / skill
    skill_md = skill_dir / "SKILL.md"
    ref_dir = skill_dir / "references"
    if not skill_md.exists() or not ref_dir.exists():
        return {}
    all_md = sorted(p for p in ref_dir.rglob("*.md"))
    step_files = [p for p in all_md if _next_step(p) is not None]
    return {
        "skill_dir": skill_dir,
        "skill_md": skill_md,
        "stages_entries": _stages_entries(skill_md),
        "skill_md_entries": _skill_md_entries(skill_md),
        "all_md": all_md,
        "step_files": step_files,
    }


@pytest.fixture(scope="module")
def skills() -> dict[str, dict]:
    return {skill: _skill_inventory(skill) for skill in WORKFLOW_SKILLS}


@pytest.mark.parametrize("skill", WORKFLOW_SKILLS)
def test_stages_entries_exist(skill: str, skills: dict[str, dict]) -> None:
    """Stages-table entries must resolve to existing files under references/."""
    info = skills[skill]
    if not info:
        pytest.skip(f"{skill}: no SKILL.md or references/")
    skill_dir = info["skill_dir"]
    missing = [
        entry for entry in info["stages_entries"] if not (skill_dir / entry).exists()
    ]
    assert not missing, (
        f"{skill}: SKILL.md Stages table references missing files: {missing}"
    )


@pytest.mark.parametrize("skill", WORKFLOW_SKILLS)
def test_next_step_files_resolve(skill: str, skills: dict[str, dict]) -> None:
    """Every `nextStepFile` value must resolve to an existing file or external target."""
    info = skills[skill]
    if not info:
        pytest.skip(f"{skill}: no SKILL.md or references/")
    broken: list[str] = []
    for step in info["step_files"]:
        nx = _next_step(step)
        if nx is None:
            continue
        if nx in EXTERNAL_TARGETS:
            external = SRC / nx
            if not external.exists():
                broken.append(
                    f"{step.relative_to(info['skill_dir']).as_posix()} → {nx} "
                    f"(external target missing at {external.as_posix()})"
                )
            continue
        resolved = _resolve_next(step, nx)
        if resolved is not None and not resolved.exists():
            broken.append(
                f"{step.relative_to(info['skill_dir']).as_posix()} → {nx} "
                f"(resolves to {resolved.as_posix()})"
            )
    assert not broken, f"{skill}: broken nextStepFile references:\n  " + "\n  ".join(
        broken
    )


@pytest.mark.parametrize("skill", WORKFLOW_SKILLS)
def test_step_files_reachable_from_skill_md(
    skill: str, skills: dict[str, dict]
) -> None:
    """Every step file must be reachable from a SKILL.md entry via the nextStepFile chain.

    Entry set is every `references/...md` path SKILL.md mentions: Stages-table
    rows plus conditional entries from On Activation (e.g. `--batch` modes).
    """
    info = skills[skill]
    if not info:
        pytest.skip(f"{skill}: no SKILL.md or references/")
    skill_dir = info["skill_dir"]

    reachable: set[pathlib.Path] = set()
    queue: deque[pathlib.Path] = deque()
    for entry in info["skill_md_entries"]:
        path = (skill_dir / entry).resolve()
        if path.exists() and path not in reachable:
            reachable.add(path)
            queue.append(path)

    while queue:
        current = queue.popleft()
        nx = _next_step(current)
        if nx is None or nx in EXTERNAL_TARGETS:
            continue
        next_path = _resolve_next(current, nx)
        if next_path is None or not next_path.exists() or next_path in reachable:
            continue
        reachable.add(next_path)
        queue.append(next_path)

    orphans = [
        step.relative_to(skill_dir).as_posix()
        for step in info["step_files"]
        if step.resolve() not in reachable
    ]
    assert not orphans, (
        f"{skill}: step files not reachable from SKILL.md entries: {orphans}"
    )

"""Structural integration tests for the step-doc-sources.md step file (story 1.3).

Validates the doc-sources step contract: correct pipeline wiring, required
sections, script reference integrity, doc_sources schema completeness in
skill-sections.md, and stages-table positioning.  Chain-reachability tests
cover link resolution; these tests cover the semantic contract.
"""

from __future__ import annotations

import pathlib
import re

import pytest

REPO_ROOT = pathlib.Path(__file__).resolve().parent.parent
CS_DIR = REPO_ROOT / "src" / "skf-create-skill"
STEP_FILE = CS_DIR / "references" / "step-doc-sources.md"
COMPILE_FILE = CS_DIR / "references" / "compile.md"
SKILL_MD = CS_DIR / "SKILL.md"
SECTIONS_FILE = CS_DIR / "assets" / "skill-sections.md"
DETECT_DOCS_SCRIPT = REPO_ROOT / "src" / "shared" / "scripts" / "skf-detect-docs.py"


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------


def _read(path: pathlib.Path) -> str:
    return path.read_text(encoding="utf-8")


def _frontmatter(path: pathlib.Path) -> str | None:
    text = _read(path)
    m = re.match(r"^---\n(.*?)\n---\n", text, re.DOTALL)
    return m.group(1) if m else None


def _next_step_value(path: pathlib.Path) -> str | None:
    fm = _frontmatter(path)
    if fm is None:
        return None
    m = re.search(r"^nextStepFile:\s*['\"]?([^'\"\n]+?)['\"]?\s*$", fm, re.MULTILINE)
    return m.group(1).strip() if m else None


# ---------------------------------------------------------------------------
# Step file existence
# ---------------------------------------------------------------------------


def test_step_file_exists() -> None:
    assert STEP_FILE.exists(), "step-doc-sources.md must exist"


# ---------------------------------------------------------------------------
# Pipeline chain values
# ---------------------------------------------------------------------------


class TestPipelineChain:
    def test_compile_points_to_step_doc_sources(self) -> None:
        assert _next_step_value(COMPILE_FILE) == "step-doc-sources.md"

    def test_step_doc_sources_points_to_validate(self) -> None:
        assert _next_step_value(STEP_FILE) == "validate.md"

    def test_validate_exists(self) -> None:
        target = (STEP_FILE.parent / "validate.md").resolve()
        assert target.exists(), "validate.md must exist for the chain to complete"


# ---------------------------------------------------------------------------
# Step file structural contract
# ---------------------------------------------------------------------------


class TestStepFileStructure:
    @pytest.fixture(scope="class")
    def text(self) -> str:
        return _read(STEP_FILE)

    def test_has_step_goal_section(self, text: str) -> None:
        assert re.search(r"^##\s+STEP GOAL", text, re.MULTILINE | re.IGNORECASE)

    def test_has_rules_section(self, text: str) -> None:
        assert re.search(r"^##\s+Rules\b", text, re.MULTILINE | re.IGNORECASE)

    def test_has_mandatory_sequence_section(self, text: str) -> None:
        assert re.search(
            r"^##\s+MANDATORY SEQUENCE", text, re.MULTILINE | re.IGNORECASE
        )

    @pytest.mark.parametrize(
        "substep",
        [
            "Check for Upstream Doc Detection Results",
            "Run Doc Detection",
            "Ensure README Entry",
            "Build doc_sources Array",
            "Update metadata.json",
            "Auto-Proceed",
        ],
    )
    def test_mandatory_sequence_substeps(self, text: str, substep: str) -> None:
        assert substep in text, f"MANDATORY SEQUENCE must include substep: {substep}"

    def test_graceful_failure_rule(self, text: str) -> None:
        assert "graceful" in text.lower(), (
            "step must document graceful failure behaviour"
        )

    def test_no_user_interaction_rule(self, text: str) -> None:
        assert re.search(r"auto.proceed|no user interaction", text, re.IGNORECASE), (
            "step must be auto-proceed (no user interaction)"
        )


# ---------------------------------------------------------------------------
# Script reference integrity
# ---------------------------------------------------------------------------


class TestScriptReference:
    @pytest.fixture(scope="class")
    def text(self) -> str:
        return _read(STEP_FILE)

    def test_references_detect_docs_script(self, text: str) -> None:
        assert "skf-detect-docs.py" in text, (
            "step must reference the detect-docs script"
        )

    def test_detect_docs_script_exists(self) -> None:
        assert DETECT_DOCS_SCRIPT.exists(), (
            "skf-detect-docs.py must exist on disk"
        )

    def test_references_uv_run_invocation(self, text: str) -> None:
        assert "uv run" in text, "step must invoke script via uv run"

    def test_documents_exit_codes(self, text: str) -> None:
        for code in ("Exit 0", "Exit 1", "Exit 2"):
            assert code in text, f"step must document {code} handling"


# ---------------------------------------------------------------------------
# doc_sources schema in skill-sections.md
# ---------------------------------------------------------------------------


class TestDocSourcesSchema:
    @pytest.fixture(scope="class")
    def schema_text(self) -> str:
        return _read(SECTIONS_FILE)

    def test_doc_sources_field_present(self, schema_text: str) -> None:
        assert "doc_sources" in schema_text

    @pytest.mark.parametrize(
        "field",
        ["url", "detected_via", "content_hash", "recorded_at"],
    )
    def test_schema_has_required_field(self, schema_text: str, field: str) -> None:
        doc_src_line = [
            line for line in schema_text.splitlines() if "doc_sources" in line
        ]
        assert any(field in line for line in doc_src_line), (
            f"doc_sources schema must include field: {field}"
        )

    def test_detected_via_includes_readme_always(self, schema_text: str) -> None:
        assert "readme_always" in schema_text, (
            "doc_sources schema must include readme_always in detected_via enum"
        )

    _EXPECTED_DETECTED_VIA = [
        "homepageUrl",
        "readme_link",
        "pages_api",
        "docs_folder",
        "readme_always",
    ]

    @pytest.mark.parametrize("value", _EXPECTED_DETECTED_VIA)
    def test_detected_via_enum_coverage(self, schema_text: str, value: str) -> None:
        assert value in schema_text, (
            f"doc_sources schema must list detected_via value: {value}"
        )

    def test_doc_sources_before_generated_by(self, schema_text: str) -> None:
        doc_idx = schema_text.find("doc_sources")
        gen_idx = schema_text.find('"generated_by"')
        assert doc_idx < gen_idx, (
            "doc_sources must appear before generated_by in schema ordering"
        )


# ---------------------------------------------------------------------------
# Stages table in SKILL.md
# ---------------------------------------------------------------------------


class TestStagesTable:
    @pytest.fixture(scope="class")
    def stages_section(self) -> str:
        text = _read(SKILL_MD)
        m = re.search(
            r"^## Stages\b(.*?)(?=^## )", text, flags=re.MULTILINE | re.DOTALL
        )
        assert m, "SKILL.md must have a ## Stages section"
        return m.group(1)

    def test_step_5a_present(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|", stages_section
        ), "Stages table must include step 5a"

    def test_step_5a_name_is_doc_sources(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|\s*Doc Sources\s*\|", stages_section
        ), "Step 5a must be named 'Doc Sources'"

    def test_step_5a_file_path(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|.*references/step-doc-sources\.md", stages_section
        ), "Step 5a must reference references/step-doc-sources.md"

    def test_step_5a_between_compile_and_validate(self, stages_section: str) -> None:
        rows = [
            line.strip()
            for line in stages_section.splitlines()
            if line.strip().startswith("|") and not line.strip().startswith("|-")
        ]
        step_nums = []
        for row in rows:
            m = re.match(r"\|\s*(\w+)\s*\|", row)
            if m and m.group(1) not in ("#", "---"):
                step_nums.append(m.group(1))
        assert "5a" in step_nums, "Step 5a must be in the stages table"
        idx_5a = step_nums.index("5a")
        idx_5 = step_nums.index("5") if "5" in step_nums else None
        idx_6 = step_nums.index("6") if "6" in step_nums else None
        assert idx_5 is not None and idx_5 < idx_5a, (
            "Step 5a must come after step 5 (Compile)"
        )
        assert idx_6 is not None and idx_5a < idx_6, (
            "Step 5a must come before step 6 (Validate)"
        )

"""Structural integration tests for the step-doc-drift.md step file (story 1.4).

Validates the doc-drift step contract: correct pipeline wiring, required
sections, graceful failure rules, drift report template positioning, and
stages-table placement in the AS workflow.
"""

from __future__ import annotations

import pathlib
import re

import pytest

REPO_ROOT = pathlib.Path(__file__).resolve().parent.parent
AS_DIR = REPO_ROOT / "src" / "skf-audit-skill"
STEP_FILE = AS_DIR / "references" / "step-doc-drift.md"
SEVERITY_CLASSIFY_FILE = AS_DIR / "references" / "severity-classify.md"
REPORT_FILE = AS_DIR / "references" / "report.md"
SKILL_MD = AS_DIR / "SKILL.md"
DRIFT_REPORT_TEMPLATE = AS_DIR / "assets" / "drift-report-template.md"


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------


def _read(path: pathlib.Path) -> str:
    return path.read_text(encoding="utf-8")


def _frontmatter(path: pathlib.Path) -> str | None:
    text = _read(path)
    m = re.match(r"^---\n(.*?)\n---\n", text, re.DOTALL)
    return m.group(1) if m else None


def _next_step_value(path: pathlib.Path) -> str | None:
    fm = _frontmatter(path)
    if fm is None:
        return None
    m = re.search(r"^nextStepFile:\s*['\"]?([^'\"\n]+?)['\"]?\s*$", fm, re.MULTILINE)
    return m.group(1).strip() if m else None


# ---------------------------------------------------------------------------
# Step file existence
# ---------------------------------------------------------------------------


def test_step_file_exists() -> None:
    assert STEP_FILE.exists(), "step-doc-drift.md must exist"


# ---------------------------------------------------------------------------
# Pipeline chain values
# ---------------------------------------------------------------------------


class TestPipelineChain:
    def test_severity_classify_points_to_step_doc_drift(self) -> None:
        assert _next_step_value(SEVERITY_CLASSIFY_FILE) == "step-doc-drift.md"

    def test_step_doc_drift_points_to_report(self) -> None:
        assert _next_step_value(STEP_FILE) == "report.md"

    def test_report_file_exists(self) -> None:
        target = (STEP_FILE.parent / "report.md").resolve()
        assert target.exists(), "report.md must exist for the chain to complete"


# ---------------------------------------------------------------------------
# Step file structural contract
# ---------------------------------------------------------------------------


class TestStepFileStructure:
    @pytest.fixture(scope="class")
    def text(self) -> str:
        return _read(STEP_FILE)

    def test_has_step_goal_section(self, text: str) -> None:
        assert re.search(r"^##\s+STEP GOAL", text, re.MULTILINE | re.IGNORECASE)

    def test_has_rules_section(self, text: str) -> None:
        assert re.search(r"^##\s+Rules\b", text, re.MULTILINE | re.IGNORECASE)

    def test_has_mandatory_sequence_section(self, text: str) -> None:
        assert re.search(
            r"^##\s+MANDATORY SEQUENCE", text, re.MULTILINE | re.IGNORECASE
        )

    @pytest.mark.parametrize(
        "substep",
        [
            "Check for doc_sources",
            "Fetch and Hash Each Tracked Doc",
            "Build Drift Findings",
            "Append to Drift Report",
            "Store Context and Auto-Proceed",
        ],
    )
    def test_mandatory_sequence_substeps(self, text: str, substep: str) -> None:
        assert substep in text, f"MANDATORY SEQUENCE must include substep: {substep}"

    def test_graceful_failure_rule(self, text: str) -> None:
        assert "graceful" in text.lower(), (
            "step must document graceful failure behaviour"
        )

    def test_no_user_interaction_rule(self, text: str) -> None:
        assert re.search(r"auto.proceed|no user interaction", text, re.IGNORECASE), (
            "step must be auto-proceed (no user interaction)"
        )

    def test_references_doc_sources(self, text: str) -> None:
        assert "doc_sources" in text, "step must reference doc_sources from metadata"

    def test_references_content_hash(self, text: str) -> None:
        assert "content_hash" in text, "step must reference content_hash for comparison"

    def test_references_sha256_convention(self, text: str) -> None:
        assert "sha256:" in text, "step must use sha256: prefix hash convention"

    def test_references_fetch_failed_status(self, text: str) -> None:
        assert "fetch_failed" in text, "step must handle fetch_failed status"

    def test_references_null_hash_handling(self, text: str) -> None:
        assert "null" in text.lower(), "step must handle null content_hash entries"

    def test_references_doc_drift_summary(self, text: str) -> None:
        assert "doc_drift_summary" in text, (
            "step must store doc_drift_summary in workflow context"
        )


# ---------------------------------------------------------------------------
# Stages table in SKILL.md
# ---------------------------------------------------------------------------


class TestStagesTable:
    @pytest.fixture(scope="class")
    def stages_section(self) -> str:
        text = _read(SKILL_MD)
        m = re.search(
            r"^## Stages\b(.*?)(?=^## )", text, flags=re.MULTILINE | re.DOTALL
        )
        assert m, "SKILL.md must have a ## Stages section"
        return m.group(1)

    def test_step_5a_present(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|", stages_section
        ), "Stages table must include step 5a"

    def test_step_5a_name_is_doc_drift(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|\s*Doc Drift\s*\|", stages_section
        ), "Step 5a must be named 'Doc Drift'"

    def test_step_5a_file_path(self, stages_section: str) -> None:
        assert re.search(
            r"\|\s*5a\s*\|.*references/step-doc-drift\.md", stages_section
        ), "Step 5a must reference references/step-doc-drift.md"

    def test_step_5a_between_severity_classify_and_report(
        self, stages_section: str
    ) -> None:
        rows = [
            line.strip()
            for line in stages_section.splitlines()
            if line.strip().startswith("|") and not line.strip().startswith("|-")
        ]
        step_nums = []
        for row in rows:
            m = re.match(r"\|\s*(\w+)\s*\|", row)
            if m and m.group(1) not in ("#", "---"):
                step_nums.append(m.group(1))
        assert "5a" in step_nums, "Step 5a must be in the stages table"
        idx_5a = step_nums.index("5a")
        idx_5 = step_nums.index("5") if "5" in step_nums else None
        idx_6 = step_nums.index("6") if "6" in step_nums else None
        assert idx_5 is not None and idx_5 < idx_5a, (
            "Step 5a must come after step 5 (Severity Classification)"
        )
        assert idx_6 is not None and idx_5a < idx_6, (
            "Step 5a must come before step 6 (Report)"
        )


# ---------------------------------------------------------------------------
# Drift report template
# ---------------------------------------------------------------------------


class TestDriftReportTemplate:
    @pytest.fixture(scope="class")
    def text(self) -> str:
        return _read(DRIFT_REPORT_TEMPLATE)

    def test_has_documentation_drift_section(self, text: str) -> None:
        assert re.search(
            r"^## Documentation Drift", text, re.MULTILINE
        ), "drift-report-template.md must include a ## Documentation Drift section"

    def test_doc_drift_after_severity_classification(self, text: str) -> None:
        sev_idx = text.find("## Severity Classification")
        doc_idx = text.find("## Documentation Drift")
        assert sev_idx != -1, "Template must have ## Severity Classification"
        assert doc_idx != -1, "Template must have ## Documentation Drift"
        assert sev_idx < doc_idx, (
            "## Documentation Drift must come after ## Severity Classification"
        )

    def test_doc_drift_before_remediation_suggestions(self, text: str) -> None:
        doc_idx = text.find("## Documentation Drift")
        rem_idx = text.find("## Remediation Suggestions")
        assert doc_idx != -1, "Template must have ## Documentation Drift"
        assert rem_idx != -1, "Template must have ## Remediation Suggestions"
        assert doc_idx < rem_idx, (
            "## Documentation Drift must come before ## Remediation Suggestions"
        )

    def test_full_section_ordering(self, text: str) -> None:
        """All template sections must appear in the canonical order."""
        sections = [
            "## Structural Drift",
            "## Semantic Drift",
            "## Severity Classification",
